-- math: Place Value to 1000
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Place Value to 1000", "body": "A three-digit number is made of hundreds, tens, and ones. In 482 the 4 means 400."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is the value of the digit 7 in 782? (Write the number, e.g. 300)\n\nThe answer is \"700\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is the value of the digit 3 in 403? (Write the number, e.g. 300)\n\nThe answer is \"3\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is the value of the digit 4 in 554? (Write the number, e.g. 300)\n\nThe answer is \"4\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  What is the value of the digit 4 in 345? (Write the number, e.g. 300)\n\nThe answer is 40."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  What is the value of the digit 3 in 352? (Write the number, e.g. 300)\n\nThe answer is 300."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  What is the value of the digit 3 in 134? (Write the number, e.g. 300)\n\nThe answer is 30."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Place Value to 1000! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$place-value-to-1000$tl$ and t.grade_level = 2);

