-- math: Money
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Money", "body": "Count coins: a quarter is 25 cents, a dime 10, a nickel 5, and a penny 1."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  You have 1 quarter, 2 dimes, 3 nickels, 1 penny. How many cents is that in all? (quarter=25, dime=10, nickel=5, penny=1)\n\nThe answer is \"61\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  You have 3 quarters, 1 dime, 2 nickels, 1 penny. How many cents is that in all? (quarter=25, dime=10, nickel=5, penny=1)\n\nThe answer is \"96\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  You have 2 quarters, 2 nickels, 2 pennies. How many cents is that in all? (quarter=25, dime=10, nickel=5, penny=1)\n\nThe answer is \"62\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  You have 1 quarter, 4 dimes, 1 nickel. How many cents is that in all? (quarter=25, dime=10, nickel=5, penny=1)\n\nThe answer is 70."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  You have 2 quarters, 2 nickels. How many cents is that in all? (quarter=25, dime=10, nickel=5, penny=1)\n\nThe answer is 60."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  You have 2 dimes, 3 pennies. How many cents is that in all? (quarter=25, dime=10, nickel=5, penny=1)\n\nThe answer is 23."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Money! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
