-- science: What Plants Need
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: What Plants Need", "body": "Plants need water and sunlight to grow and make their own food."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  To grow well, plants need water, air, and:\n\nThe answer is \"sunlight\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A plant kept in a dark closet with no light will:\n\nThe answer is \"grow poorly or die\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Plants take in water mostly through their:\n\nThe answer is \"roots\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Leaves use sunlight to help make the plant's:", "choices": [{"id": "a", "label": "roots"}, {"id": "b", "label": "soil"}, {"id": "c", "label": "food"}, {"id": "d", "label": "rocks"}], "answer": "c", "explanation": "Yes! The answer is \"food\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "If you never water a plant, it will:", "choices": [{"id": "a", "label": "grow taller"}, {"id": "b", "label": "dry out and wilt"}, {"id": "c", "label": "turn blue"}, {"id": "d", "label": "make rain"}], "answer": "b", "explanation": "Yes! The answer is \"dry out and wilt\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which two things does a plant need from its surroundings?", "choices": [{"id": "a", "label": "candy and toys"}, {"id": "b", "label": "TV and music"}, {"id": "c", "label": "water and sunlight"}, {"id": "d", "label": "plastic and metal"}], "answer": "c", "explanation": "Yes! The answer is \"water and sunlight\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about What Plants Need! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
