  where s.slug = $tl$science$tl$ and t.slug = $tl$plants-need-sun-and-water$tl$ and t.grade_level = 2);

-- science: Seeds & Pollination
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Seeds & Pollination", "body": "Animals and wind help plants by moving pollen and spreading seeds to new places."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Many plants make ____ that can grow into new plants.\n\nThe answer is \"seeds\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Bees help plants by moving:\n\nThe answer is \"pollen from flower to flower\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Moving pollen between flowers is called:\n\nThe answer is \"pollination\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Some seeds are spread by sticking to animal:", "choices": [{"id": "a", "label": "teeth"}, {"id": "b", "label": "eyes"}, {"id": "c", "label": "fur"}, {"id": "d", "label": "ears only"}], "answer": "c", "explanation": "Yes! The answer is \"fur\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A dandelion's fluffy seeds are spread by the:", "choices": [{"id": "a", "label": "ocean"}, {"id": "b", "label": "wind"}, {"id": "c", "label": "fire"}, {"id": "d", "label": "Moon"}], "answer": "b", "explanation": "Yes! The answer is \"wind\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "When an animal eats a fruit, it can spread the:", "choices": [{"id": "a", "label": "leaves"}, {"id": "b", "label": "roots"}, {"id": "c", "label": "seeds inside"}, {"id": "d", "label": "petals"}], "answer": "c", "explanation": "Yes! The answer is \"seeds inside\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Seeds & Pollination! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
