  where s.slug = $tl$science$tl$ and t.slug = $tl$seeds-and-pollination$tl$ and t.grade_level = 2);

-- science: Habitats & Diversity
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Habitats & Diversity", "body": "Different habitats are home to many different kinds of plants and animals."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The natural home of a living thing is its:\n\nThe answer is \"habitat\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which animal best fits a desert habitat?\n\nThe answer is \"a lizard\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which animal best fits a cold, icy habitat?\n\nThe answer is \"a polar bear\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A pond habitat is home to:", "choices": [{"id": "a", "label": "camels"}, {"id": "b", "label": "polar bears"}, {"id": "c", "label": "lions"}, {"id": "d", "label": "frogs and fish"}], "answer": "d", "explanation": "Yes! The answer is \"frogs and fish\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Different habitats are home to different kinds of:", "choices": [{"id": "a", "label": "cars"}, {"id": "b", "label": "plants and animals"}, {"id": "c", "label": "toys"}, {"id": "d", "label": "phones"}], "answer": "b", "explanation": "Yes! The answer is \"plants and animals\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A rainforest habitat is:", "choices": [{"id": "a", "label": "cold and dry"}, {"id": "b", "label": "sandy and dry"}, {"id": "c", "label": "icy"}, {"id": "d", "label": "warm and very rainy"}], "answer": "d", "explanation": "Yes! The answer is \"warm and very rainy\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Habitats & Diversity! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
