-- science: Fast & Slow Earth Changes
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Fast & Slow Earth Changes", "body": "Some land changes happen quickly (volcanoes, floods) and some slowly (erosion)."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which change to the land happens FAST?\n\nThe answer is \"a volcano erupting\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which change to the land happens SLOWLY?\n\nThe answer is \"a canyon being carved by a river\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  An earthquake changes the land:\n\nThe answer is \"quickly\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Water slowly wearing away rock over many years is:", "choices": [{"id": "a", "label": "a fast flood"}, {"id": "b", "label": "an earthquake"}, {"id": "c", "label": "a volcano"}, {"id": "d", "label": "slow erosion"}], "answer": "d", "explanation": "Yes! The answer is \"slow erosion\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A sudden flood can change the land:", "choices": [{"id": "a", "label": "quickly"}, {"id": "b", "label": "very slowly"}, {"id": "c", "label": "never"}, {"id": "d", "label": "only at night"}], "answer": "a", "explanation": "Yes! The answer is \"quickly\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Wind slowly shaping a sand dune is a change that is:", "choices": [{"id": "a", "label": "instant"}, {"id": "b", "label": "explosive"}, {"id": "c", "label": "loud"}, {"id": "d", "label": "slow"}], "answer": "d", "explanation": "Yes! The answer is \"slow\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Fast & Slow Earth Changes! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
