-- science: Landforms & Maps
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Landforms & Maps", "body": "Earth has mountains, valleys, rivers, and oceans, and maps show where they are."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A tall landform that rises high above the land is a:\n\nThe answer is \"mountain\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A large body of salt water is an:\n\nThe answer is \"ocean\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A map uses symbols and a key to show:\n\nThe answer is \"places and land features\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A low area of land between mountains is a:", "choices": [{"id": "a", "label": "peak"}, {"id": "b", "label": "valley"}, {"id": "c", "label": "cliff"}, {"id": "d", "label": "plateau"}], "answer": "b", "explanation": "Yes! The answer is \"valley\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A flat, wide area of land is a:", "choices": [{"id": "a", "label": "mountain"}, {"id": "b", "label": "canyon"}, {"id": "c", "label": "plain"}, {"id": "d", "label": "volcano"}], "answer": "c", "explanation": "Yes! The answer is \"plain\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "On many maps, which direction is at the top?", "choices": [{"id": "a", "label": "north"}, {"id": "b", "label": "south"}, {"id": "c", "label": "east"}, {"id": "d", "label": "down"}], "answer": "a", "explanation": "Yes! The answer is \"north\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Landforms & Maps! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
