-- science: Water on Earth
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Water on Earth", "body": "Water is found in oceans, lakes, rivers, ice, and underground; ocean water is salty."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Most of the water on Earth is found in the:\n\nThe answer is \"oceans\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Ocean water is:\n\nThe answer is \"salty\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which holds fresh water we can drink?\n\nThe answer is \"a lake or river\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Frozen water at the cold poles is found as:", "choices": [{"id": "a", "label": "sand"}, {"id": "b", "label": "ice"}, {"id": "c", "label": "soil"}, {"id": "d", "label": "steam"}], "answer": "b", "explanation": "Yes! The answer is \"ice\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which is a body of fresh water?", "choices": [{"id": "a", "label": "a pond"}, {"id": "b", "label": "the ocean"}, {"id": "c", "label": "a sea"}, {"id": "d", "label": "a salty bay"}], "answer": "a", "explanation": "Yes! The answer is \"a pond\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Water in the sky inside clouds is made of tiny:", "choices": [{"id": "a", "label": "rocks"}, {"id": "b", "label": "sand"}, {"id": "c", "label": "water droplets"}, {"id": "d", "label": "smoke"}], "answer": "c", "explanation": "Yes! The answer is \"water droplets\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Water on Earth! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
