-- science: Wind & Water Shape Land
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Wind & Water Shape Land", "body": "Wind and water slowly wear away and move soil and rock, changing the land."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Moving water can carry away soil and sand. This is:\n\nThe answer is \"erosion\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Wind can shape the land by moving:\n\nThe answer is \"sand into dunes\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A river slowly carving a path through rock makes a:\n\nThe answer is \"canyon or valley\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Ocean waves hitting a cliff cause the cliff to:", "choices": [{"id": "a", "label": "wear away"}, {"id": "b", "label": "grow taller"}, {"id": "c", "label": "get colder"}, {"id": "d", "label": "turn to metal"}], "answer": "a", "explanation": "Yes! The answer is \"wear away\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which slows down soil erosion on a hill?", "choices": [{"id": "a", "label": "removing all plants"}, {"id": "b", "label": "planting grass and trees"}, {"id": "c", "label": "adding loose sand"}, {"id": "d", "label": "pouring more water"}], "answer": "b", "explanation": "Yes! The answer is \"planting grass and trees\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "When a river drops the sand it carried, it builds up:", "choices": [{"id": "a", "label": "a mountain instantly"}, {"id": "b", "label": "a cloud"}, {"id": "c", "label": "a canyon"}, {"id": "d", "label": "new land (deposition)"}], "answer": "d", "explanation": "Yes! The answer is \"new land (deposition)\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Wind & Water Shape Land! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
