-- reading: Main Idea
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Main Idea", "body": "The main idea is the most important point a text makes."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Honeybees are helpful. They make honey and help flowers grow by moving pollen.\" The main idea is that honeybees:\n\nThe answer is \"are helpful\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Recycling is good. It saves trees, uses less energy, and keeps trash out of landfills.\" The main idea is that recycling:\n\nThe answer is \"is good for the Earth\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Penguins stay warm with thick feathers, a layer of fat, and by huddling together.\" The passage is mostly about how penguins:\n\nThe answer is \"stay warm\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Our class garden grew well. We planted seeds, watered them, and pulled weeds.\" The main idea is that the class:", "choices": [{"id": "a", "label": "went on a trip"}, {"id": "b", "label": "grew a garden"}, {"id": "c", "label": "had a party"}, {"id": "d", "label": "read books"}], "answer": "b", "explanation": "Yes! The answer is \"grew a garden\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Firefighters are brave. They put out fires, rescue people, and teach safety.\" The main idea is that firefighters:", "choices": [{"id": "a", "label": "are tall"}, {"id": "b", "label": "drive fast"}, {"id": "c", "label": "do an important job"}, {"id": "d", "label": "like red"}], "answer": "c", "explanation": "Yes! The answer is \"do an important job\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Sea turtles travel far in the ocean and return to the beach where they were born.\" The main idea is that sea turtles:", "choices": [{"id": "a", "label": "travel far and return home"}, {"id": "b", "label": "eat plants"}, {"id": "c", "label": "are small"}, {"id": "d", "label": "sleep a lot"}], "answer": "a", "explanation": "Yes! The answer is \"travel far and return home\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Main Idea! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$main-idea$tl$ and t.grade_level = 2);

-- reading: Key Details
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Key Details", "body": "Key details are the facts that tell more about the main idea."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"The hike was perfect. We saw a calm lake, tall pines, and a fire pit.\" Which detail was on the hike?\n\nThe answer is \"a calm lake\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Our hamster runs on its wheel, stuffs food in its cheeks, and naps a lot.\" Which detail is true?\n\nThe answer is \"it runs on its wheel\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"The storm was fierce: lightning flashed and wind bent the trees.\" Which detail shows it was fierce?\n\nThe answer is \"wind bent the trees\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Grandpa grows tomatoes, sunflowers, and sweet strawberries.\" Which does Grandpa grow?", "choices": [{"id": "a", "label": "a car"}, {"id": "b", "label": "strawberries"}, {"id": "c", "label": "a boat"}, {"id": "d", "label": "a kite"}], "answer": "b", "explanation": "Yes! The answer is \"strawberries\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"At the museum we saw dinosaur bones, old coins, and paintings.\" Which detail is true?", "choices": [{"id": "a", "label": "the bus was late"}, {"id": "b", "label": "we saw dinosaur bones"}, {"id": "c", "label": "lunch was good"}, {"id": "d", "label": "it was sunny"}], "answer": "b", "explanation": "Yes! The answer is \"we saw dinosaur bones\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"My brother carries groceries, walks the dog, and helps with homework.\" Which detail shows he helps?", "choices": [{"id": "a", "label": "he walks the dog"}, {"id": "b", "label": "he watches TV all day"}, {"id": "c", "label": "he is tall"}, {"id": "d", "label": "he likes pizza"}], "answer": "a", "explanation": "Yes! The answer is \"he walks the dog\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Key Details! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$key-details$tl$ and t.grade_level = 2);

-- reading: Story Lessons
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Story Lessons", "body": "Many stories teach a lesson or moral about how to live or treat others."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"The hare bragged and napped during the race. The slow tortoise kept going and won.\" The lesson is:\n\nThe answer is \"slow and steady wins the race\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"The ant worked all summer storing food. The grasshopper played and had none in winter.\" The lesson is:\n\nThe answer is \"plan ahead and work hard\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Maya kept trying to ride her bike, fell many times, but finally did it.\" The lesson is:\n\nThe answer is \"don't give up\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Leo shared his snack, and his friend shared back the next day.\" The lesson is:", "choices": [{"id": "a", "label": "never share"}, {"id": "b", "label": "being kind comes back to you"}, {"id": "c", "label": "food is bad"}, {"id": "d", "label": "friends are mean"}], "answer": "b", "explanation": "Yes! The answer is \"being kind comes back to you\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The boy cried 'wolf' as a joke so often that no one believed him when it was real.\" The lesson is:", "choices": [{"id": "a", "label": "tell the truth"}, {"id": "b", "label": "jokes are great"}, {"id": "c", "label": "wolves are nice"}, {"id": "d", "label": "shout a lot"}], "answer": "a", "explanation": "Yes! The answer is \"tell the truth\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Ana told the truth even though she was scared, and her mom was proud.\" The lesson is:", "choices": [{"id": "a", "label": "hide mistakes"}, {"id": "b", "label": "never speak"}, {"id": "c", "label": "honesty is important"}, {"id": "d", "label": "fear is bad"}], "answer": "c", "explanation": "Yes! The answer is \"honesty is important\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Story Lessons! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$story-lesson$tl$ and t.grade_level = 2);

-- reading: Character Feelings
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Character Feelings", "body": "Look at what characters do and say to understand how they feel."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Tia smiled wide and hugged her trophy.\" How does Tia feel?\n\nThe answer is \"happy / proud\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Ben's eyes filled with tears when his balloon popped.\" How does Ben feel?\n\nThe answer is \"sad\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Mia stomped her feet and crossed her arms.\" How does Mia feel?\n\nThe answer is \"angry\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Leo hid under the blanket during the loud storm.\" How does Leo feel?", "choices": [{"id": "a", "label": "proud"}, {"id": "b", "label": "scared"}, {"id": "c", "label": "bored"}, {"id": "d", "label": "silly"}], "answer": "b", "explanation": "Yes! The answer is \"scared\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Ana jumped up and down when she heard the great news.\" How does Ana feel?", "choices": [{"id": "a", "label": "sad"}, {"id": "b", "label": "angry"}, {"id": "c", "label": "tired"}, {"id": "d", "label": "excited"}], "answer": "d", "explanation": "Yes! The answer is \"excited\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Sam yawned and rubbed his eyes at bedtime.\" How does Sam feel?", "choices": [{"id": "a", "label": "excited"}, {"id": "b", "label": "angry"}, {"id": "c", "label": "scared"}, {"id": "d", "label": "sleepy"}], "answer": "d", "explanation": "Yes! The answer is \"sleepy\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Character Feelings! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$character-feelings$tl$ and t.grade_level = 2);

-- reading: Sequence of Events
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Sequence of Events", "body": "Sequence is the order things happen: first, next, then, and last."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"First Ana woke up. Next she ate. Then she went to school.\" What did Ana do FIRST?\n\nThe answer is \"woke up\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"He read the recipe, gathered the food, then cooked.\" What did he do BEFORE cooking?\n\nThe answer is \"gathered the food\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"The caterpillar ate leaves, made a chrysalis, then became a butterfly.\" What happened LAST?\n\nThe answer is \"it became a butterfly\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"We bought tickets, found our seats, and watched the show.\" What came SECOND?", "choices": [{"id": "a", "label": "bought tickets"}, {"id": "b", "label": "found our seats"}, {"id": "c", "label": "watched the show"}, {"id": "d", "label": "went home"}], "answer": "b", "explanation": "Yes! The answer is \"found our seats\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"First fill the pot, next turn on the stove, then add pasta.\" What is the SECOND step?", "choices": [{"id": "a", "label": "add pasta"}, {"id": "b", "label": "turn on the stove"}, {"id": "c", "label": "fill the pot"}, {"id": "d", "label": "eat"}], "answer": "b", "explanation": "Yes! The answer is \"turn on the stove\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"She drew a picture, colored it, then hung it up.\" What did she do LAST?", "choices": [{"id": "a", "label": "drew it"}, {"id": "b", "label": "hung it up"}, {"id": "c", "label": "colored it"}, {"id": "d", "label": "erased it"}], "answer": "b", "explanation": "Yes! The answer is \"hung it up\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Sequence of Events! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$sequence$tl$ and t.grade_level = 2);

-- reading: Cause & Effect
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Cause & Effect", "body": "A cause is why something happens; the effect is what happens."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"It rained all day, so the game was canceled.\" What was the CAUSE?\n\nThe answer is \"it rained all day\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Tom forgot to water his plant, so it wilted.\" What was the EFFECT?\n\nThe answer is \"the plant wilted\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"The ice melted because the day was hot.\" Why did the ice melt?\n\nThe answer is \"the day was hot\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"She studied hard, so she passed the test.\" What caused her to pass?", "choices": [{"id": "a", "label": "the test was easy"}, {"id": "b", "label": "she was late"}, {"id": "c", "label": "she studied hard"}, {"id": "d", "label": "she slept"}], "answer": "c", "explanation": "Yes! The answer is \"she studied hard\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The dog barked loudly, so the baby woke up.\" What was the effect of the barking?", "choices": [{"id": "a", "label": "the dog slept"}, {"id": "b", "label": "the baby woke up"}, {"id": "c", "label": "the baby ate"}, {"id": "d", "label": "the dog ran"}], "answer": "b", "explanation": "Yes! The answer is \"the baby woke up\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Because the road was icy, the cars drove slowly.\" Why did the cars drive slowly?", "choices": [{"id": "a", "label": "the road was icy"}, {"id": "b", "label": "the cars were red"}, {"id": "c", "label": "it was sunny"}, {"id": "d", "label": "the road was new"}], "answer": "a", "explanation": "Yes! The answer is \"the road was icy\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Cause & Effect! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$cause-and-effect$tl$ and t.grade_level = 2);

-- reading: Vocabulary in Context
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Vocabulary in Context", "body": "Use the words around an unknown word to figure out its meaning."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"The path was narrow, so only one person could pass.\" What does \"narrow\" mean?\n\nThe answer is \"not wide\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"The soup was scalding, so she let it cool.\" What does \"scalding\" mean?\n\nThe answer is \"very hot\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"He was exhausted after the long run.\" What does \"exhausted\" mean?\n\nThe answer is \"very tired\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The ancient ruins were thousands of years old.\" What does \"ancient\" mean?", "choices": [{"id": "a", "label": "brand new"}, {"id": "b", "label": "colorful"}, {"id": "c", "label": "very old"}, {"id": "d", "label": "tiny"}], "answer": "c", "explanation": "Yes! The answer is \"very old\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The timid puppy hid behind the couch.\" What does \"timid\" mean?", "choices": [{"id": "a", "label": "shy or fearful"}, {"id": "b", "label": "loud"}, {"id": "c", "label": "huge"}, {"id": "d", "label": "fast"}], "answer": "a", "explanation": "Yes! The answer is \"shy or fearful\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The enormous elephant was the biggest animal there.\" What does \"enormous\" mean?", "choices": [{"id": "a", "label": "very large"}, {"id": "b", "label": "very small"}, {"id": "c", "label": "very fast"}, {"id": "d", "label": "very quiet"}], "answer": "a", "explanation": "Yes! The answer is \"very large\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Vocabulary in Context! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$context-clues$tl$ and t.grade_level = 2);

-- reading: Synonyms & Antonyms
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Synonyms & Antonyms", "body": "Synonyms mean almost the same; antonyms mean the opposite."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which word means almost the same as \"happy\"?\n\nThe answer is \"glad\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which word is the OPPOSITE of \"big\"?\n\nThe answer is \"small\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A synonym for \"fast\" is:\n\nThe answer is \"quick\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The opposite of \"hot\" is:", "choices": [{"id": "a", "label": "warm"}, {"id": "b", "label": "boiling"}, {"id": "c", "label": "sunny"}, {"id": "d", "label": "cold"}], "answer": "d", "explanation": "Yes! The answer is \"cold\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A synonym for \"begin\" is:", "choices": [{"id": "a", "label": "stop"}, {"id": "b", "label": "start"}, {"id": "c", "label": "end"}, {"id": "d", "label": "finish"}], "answer": "b", "explanation": "Yes! The answer is \"start\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "An antonym for \"empty\" is:", "choices": [{"id": "a", "label": "bare"}, {"id": "b", "label": "hollow"}, {"id": "c", "label": "full"}, {"id": "d", "label": "vacant"}], "answer": "c", "explanation": "Yes! The answer is \"full\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Synonyms & Antonyms! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$synonyms-and-antonyms$tl$ and t.grade_level = 2);

-- reading: Fact vs. Opinion
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Fact vs. Opinion", "body": "A fact can be proven; an opinion tells what someone feels."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which sentence is a FACT?\n\nThe answer is \"Water freezes when it gets very cold.\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which sentence is an OPINION?\n\nThe answer is \"Recess is the most fun part of the day.\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which is a FACT?\n\nThe answer is \"A triangle has three sides.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which is an OPINION?", "choices": [{"id": "a", "label": "Chocolate is the best flavor."}, {"id": "b", "label": "Ice melts when heated."}, {"id": "c", "label": "There are 12 months."}, {"id": "d", "label": "Plants need sunlight."}], "answer": "a", "explanation": "Yes! The answer is \"Chocolate is the best flavor.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "\"Our school has 300 students.\" This is a:", "choices": [{"id": "a", "label": "opinion"}, {"id": "b", "label": "fact"}, {"id": "c", "label": "question"}, {"id": "d", "label": "story"}], "answer": "b", "explanation": "Yes! The answer is \"fact\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "\"Reading is more fun than TV.\" This is an:", "choices": [{"id": "a", "label": "fact"}, {"id": "b", "label": "rule"}, {"id": "c", "label": "number"}, {"id": "d", "label": "opinion"}], "answer": "d", "explanation": "Yes! The answer is \"opinion\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Fact vs. Opinion! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$fact-and-opinion$tl$ and t.grade_level = 2);

-- reading: Comparing Texts
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Comparing Texts", "body": "We can compare two texts to see how they are alike and different."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  One book says dogs make great pets; another says cats do. Both books are about:\n\nThe answer is \"good pets\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Two stories both have a brave hero, but one is in space and one is under the sea. They are alike because both have:\n\nThe answer is \"a brave hero\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Book A is about how rain forms; Book B is about how snow forms. Both are about:\n\nThe answer is \"kinds of weather\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "One text says summer is best; another says winter is best. They differ on the best:", "choices": [{"id": "a", "label": "color"}, {"id": "b", "label": "number"}, {"id": "c", "label": "letter"}, {"id": "d", "label": "season"}], "answer": "d", "explanation": "Yes! The answer is \"season\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Two articles describe bees and butterflies. Both insects:", "choices": [{"id": "a", "label": "live in water"}, {"id": "b", "label": "have fur"}, {"id": "c", "label": "help pollinate flowers"}, {"id": "d", "label": "bark"}], "answer": "c", "explanation": "Yes! The answer is \"help pollinate flowers\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Story 1 ends happily; Story 2 ends sadly. They differ in their:", "choices": [{"id": "a", "label": "title only"}, {"id": "b", "label": "ending"}, {"id": "c", "label": "number of pages only"}, {"id": "d", "label": "author's name"}], "answer": "b", "explanation": "Yes! The answer is \"ending\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Comparing Texts! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$compare-texts$tl$ and t.grade_level = 2);

