update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Nouns", "body": "A noun names a person, place, thing, or idea."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which word is a noun (a person, place, or thing)?\n\nThe answer is \"engine\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which word is a noun (a person, place, or thing)?\n\nThe answer is \"doctor\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which word is a noun (a person, place, or thing)?\n\nThe answer is \"forest\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is a noun (a person, place, or thing)?", "choices": [{"id": "a", "label": "gentle"}, {"id": "b", "label": "window"}, {"id": "c", "label": "wander"}, {"id": "d", "label": "whisper"}], "answer": "b", "explanation": "Yes! The answer is \"window\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is a noun (a person, place, or thing)?", "choices": [{"id": "a", "label": "curious"}, {"id": "b", "label": "mountain"}, {"id": "c", "label": "narrow"}, {"id": "d", "label": "ancient"}], "answer": "b", "explanation": "Yes! The answer is \"mountain\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is a noun (a person, place, or thing)?", "choices": [{"id": "a", "label": "golden"}, {"id": "b", "label": "library"}, {"id": "c", "label": "cheerful"}, {"id": "d", "label": "stormy"}], "answer": "b", "explanation": "Yes! The answer is \"library\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Nouns! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
