update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Action Verbs", "body": "A verb shows action - what the subject does."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which word is an action verb (something you can do)?\n\nThe answer is \"discover\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which word is an action verb (something you can do)?\n\nThe answer is \"explore\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which word is an action verb (something you can do)?\n\nThe answer is \"gallop\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is an action verb (something you can do)?", "choices": [{"id": "a", "label": "gentle"}, {"id": "b", "label": "puppy"}, {"id": "c", "label": "wander"}, {"id": "d", "label": "sister"}], "answer": "c", "explanation": "Yes! The answer is \"wander\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is an action verb (something you can do)?", "choices": [{"id": "a", "label": "whisper"}, {"id": "b", "label": "pencil"}, {"id": "c", "label": "stormy"}, {"id": "d", "label": "window"}], "answer": "a", "explanation": "Yes! The answer is \"whisper\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is an action verb (something you can do)?", "choices": [{"id": "a", "label": "blanket"}, {"id": "b", "label": "frozen"}, {"id": "c", "label": "slippery"}, {"id": "d", "label": "scribble"}], "answer": "d", "explanation": "Yes! The answer is \"scribble\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Action Verbs! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
