update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Subject-Verb Agreement", "body": "The verb must match the subject, like 'The dog runs.'"}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Choose the correct verb: \"The rabbit ____ every day.\"\n\nThe answer is \"hops\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Choose the correct verb: \"The baby ____ every day.\"\n\nThe answer is \"cries\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Choose the correct verb: \"The singer ____ every day.\"\n\nThe answer is \"performs\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Choose the correct verb: \"The bird ____ every day.\"", "choices": [{"id": "a", "label": "sing"}, {"id": "b", "label": "singsed"}, {"id": "c", "label": "singsing"}, {"id": "d", "label": "sings"}], "answer": "d", "explanation": "Yes! The answer is \"sings\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Choose the correct verb: \"The engine ____ every day.\"", "choices": [{"id": "a", "label": "roar"}, {"id": "b", "label": "roars"}, {"id": "c", "label": "roarsed"}, {"id": "d", "label": "roarsing"}], "answer": "b", "explanation": "Yes! The answer is \"roars\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Choose the correct verb: \"The girl ____ every day.\"", "choices": [{"id": "a", "label": "run"}, {"id": "b", "label": "runs"}, {"id": "c", "label": "runsed"}, {"id": "d", "label": "runsing"}], "answer": "b", "explanation": "Yes! The answer is \"runs\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Subject-Verb Agreement! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
